public static DiskLruCache open(File directory, int appVersion, int valueCount, long maxSize)
            throws IOException {
        if (maxSize <= 0) {
            throw new IllegalArgumentException("maxSize <= 0");
        }
        if (valueCount <= 0) {
            throw new IllegalArgumentException("valueCount <= 0");
        }

        // prefer to pick up where we left off
        DiskLruCache cache = new DiskLruCache(directory, appVersion, valueCount, maxSize);
        if (cache.journalFile.exists()) {
            try {
                cache.readJournal();
                cache.processJournal();
                cache.journalWriter = new BufferedWriter(new FileWriter(cache.journalFile, true));
                return cache;
            } catch (IOException journalIsCorrupt) {
                System.out.println("DiskLruCache " + directory + " is corrupt: "
                        + journalIsCorrupt.getMessage() + ", removing");
                cache.delete();
            }
        }

        // create a new empty cache
        directory.mkdirs();
        cache = new DiskLruCache(directory, appVersion, valueCount, maxSize);
        cache.rebuildJournal();
        return cache;
    }

public static InputStream unTarOneFile(InputStream tarGzInputStream, final String filename)
      throws FileNotFoundException, IOException, ArchiveException {
    TarArchiveInputStream debInputStream = null;
    InputStream is = null;
    try {
      is = new GzipCompressorInputStream(tarGzInputStream);
      debInputStream = (TarArchiveInputStream) new ArchiveStreamFactory().createArchiveInputStream("tar", is);
      TarArchiveEntry entry = null;
      while ((entry = (TarArchiveEntry) debInputStream.getNextEntry()) != null) {
        if (entry.getName().contains(filename)) {
          ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
          IOUtils.copy(debInputStream, byteArrayOutputStream);
          return new ByteArrayInputStream(byteArrayOutputStream.toByteArray());
        }
      }
    } finally {
      IOUtils.closeQuietly(debInputStream);
      IOUtils.closeQuietly(is);
    }
    return null;
  }

@Override
    public boolean isFileOutOfThisFormat(String filepath) {
        if (!filepath.matches("(?i)^.+\\.txt$")) {
            return false;
        }

        File file = new File(filepath);
        boolean hasZimHeader = false;
        try {
            BufferedReader reader = new BufferedReader(new FileReader(file));
            StringBuilder firstLinesOfFile = new StringBuilder();
            for (int lineNumber = 0; lineNumber < 4; lineNumber++) {
                String line = reader.readLine();
                if (line != null) {
                    firstLinesOfFile.append(line + String.format("%n"));
                }
            }
            hasZimHeader = ZimWikiHighlighter.Patterns.ZIMHEADER.pattern.matcher(firstLinesOfFile).find();
            reader.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
        return hasZimHeader;
    }

public static void runAndScoreCorefDist(String runDistCmd, Properties props, String propsFile) throws Exception {
    PrintWriter pw = IOUtils.getPrintWriter(propsFile);
    props.store(pw, null);
