@Override
    protected void write(
            FeatureCollectionResponse featureCollection, OutputStream output, Operation getFeature)
            throws IOException, ServiceException {

        File file = File.createTempFile("geopkg", ".tmp.gpkg");
        GeoPackage geopkg = GeoPkg.getGeoPackage(file);

        for (FeatureCollection collection : featureCollection.getFeatures()) {

            FeatureEntry e = new FeatureEntry();

            if (!(collection instanceof SimpleFeatureCollection)) {
                throw new ServiceException(
                        "GeoPackage OutputFormat does not support Complex Features.");
            }

            SimpleFeatureCollection features = (SimpleFeatureCollection) collection;
            FeatureTypeInfo meta = lookupFeatureType(features);
            if (meta != null) {
                // initialize entry metadata
                e.setIdentifier(meta.getTitle());
                e.setDescription(abstractOrDescription(meta));
            }

            geopkg.add(e, features);

            if (!"false".equals(System.getProperty(PROPERTY_INDEXED))) {
                geopkg.createSpatialIndex(e);
            }
        }

        geopkg.close();

        // write to output and delete temporary file
        InputStream temp = new FileInputStream(geopkg.getFile());
        IOUtils.copy(temp, output);
        output.flush();
        temp.close();
        geopkg.getFile().delete();
    }

public void load(File file) throws IOException {
		BufferedReader in = new BufferedReader(new FileReader(file));
		String line;
		while ((line = in.readLine()) != null) {
			this.addToken(line.trim());
		}
		in.close();
	}

@Override
        public void run() {
            while (!isInterrupted()) {
                try {
                    final FileInputStream fis = new FileInputStream(fifoInFile);
                    fis.read();
                    if (isInterrupted()) {
                        break;
                    }
                    fis.close();
                } catch (IOException e) {
                    e.printStackTrace();
                }
                executor.submit(() -> {
                    traceEventLoopLogger.log("before dispatching request");
                    try {
                        int res = context.eval(Source.newBuilder("R", ".fastr.dispatchNativeHandlers", "<dispatch-native-handlers>").internal(true).buildLiteral()).execute().asInt();
                        traceEventLoopLogger.log("after dispatching request, res=" + res);
                    } catch (Throwable ex) {
                        releaseFifoOut();
                        traceEventLoopLogger.log("error in dispatching request");
                        ex.printStackTrace();
                    }
                });
            }
        }

public InputStream getFileAsInputStream(String path) throws IOException {
    File explodedFile = getExplodedFile(path);
    if ((!file.exists() && !tmpFile.exists() && !explodedFile.exists())
        || removedFileSet.contains(path)) throw new FileNotFoundException(path);
    if (explodedFile.exists()) return FileUtil.getFileAsInputStream(explodedFile);

    ZipEntry entry = new ZipEntry(path);
    ZipFile zipFile = getZipFile();
    InputStream in = null;
    try {
      in = zipFile.getInputStream(entry);
      if (in == null) throw new FileNotFoundException(path);
      String type = FileUtil.getContentType(in);
      if (log.isDebugEnabled() && type != null)
        log.debug("FileUtil.getContentType() returned " + type);
      return in;
    } catch (IOException ex) {
      // Don't need to close 'in' since zipFile.close() will do so
      IOUtils.closeQuietly(in);
      throw ex;
    }
  }

@ActionDoc(text="Sends a message to an XMPP user.")
	static public boolean sendXMPP(
			@ParamDoc(name="to") String to, 
			@ParamDoc(name="message") String message) {
		boolean success = false;

		try {
			XMPPConnection conn = XMPPConnect.getConnection();

			ChatManager chatmanager = ChatManager.getInstanceFor(conn);
			Chat newChat = chatmanager.createChat(to, null);

			try {
				while(message.length()>=2000) {
					newChat.sendMessage(message.substring(0, 2000));
					message = message.substring(2000);
				}
				newChat.sendMessage(message);
				logger.debug("Sent message '{}' to '{}'.", message, to);
				success = true;
			} catch (XMPPException e) {
				logger.warn("Error Delivering block", e);
			} catch (NotConnectedException e) {
				logger.warn("Error Delivering block", e);
			}
		} catch (NotInitializedException e) {
			logger.warn("Could not send XMPP message as connection is not correctly initialized!");
		}

		return success;
	}

