@SuppressWarnings("rawtypes")
	private static void initInternal(File configFile, String outputPath, boolean stdOut) throws IOException
	{
		List<Appender> appenders = new ArrayList<Appender>();

		// Retrieve all existing appenders
		Enumeration apps = LogManager.getRootLogger().getAllAppenders();
		while(apps.hasMoreElements()) {
			Appender appender = (Appender)apps.nextElement();
			if (!(appender instanceof ConsoleAppender || appender instanceof FileAppender)) 
				appenders.add( appender );
		}

		Properties lprops = new Properties();
		FileInputStream in = new FileInputStream(configFile);
		lprops.load(in);
		in.close();
		LogManager.resetConfiguration();

		if (lprops.getProperty("log4j.appender.orslogfile.File") == null)
			lprops.put("log4j.appender.orslogfile.File", outputPath);

		PropertyConfigurator.configure(lprops);

		if (!stdOut) {
            apps = org.apache.log4j.Logger.getRootLogger().getAllAppenders();
            while (apps.hasMoreElements()) {
            	Appender appender = (Appender)apps.nextElement();
                if (appender instanceof org.apache.log4j.ConsoleAppender) {
                    org.apache.log4j.Logger.getRootLogger().removeAppender(appender);
                }
            }
		} 

		for (Appender appender : appenders ) 
			LogManager.getRootLogger().addAppender( appender );
	}

private static MaxHistory readHistory(File storedResults)
            throws CouldNotReadCoreException {
        try {
            FileInputStream file = new FileInputStream(storedResults);
            try {
                ObjectInputStream stream = new ObjectInputStream(file);
                try {
                    return (MaxHistory) stream.readObject();
                } finally {
                    stream.close();
                }
            } finally {
                file.close();
            }
        } catch (Exception e) {
            throw new CouldNotReadCoreException(e);
        }
    }

@Override
  public void cacheGameProperties(final GameData gameData) {
    final Map<String, Object> serializableMap = new HashMap<>();
    for (final IEditableProperty property : gameData.getProperties().getEditableProperties()) {
      if (property.getValue() instanceof Serializable) {
        serializableMap.put(property.getName(), property.getValue());
      }
    }
    final File cache = getCacheFile(gameData);
    try {
      // create the directory if it doesn't already exists
      if (!cache.getParentFile().exists()) {
        cache.getParentFile().mkdirs();
      }
      final ObjectOutputStream out = new ObjectOutputStream(new FileOutputStream(cache));
      out.writeObject(serializableMap);
      out.close();
    } catch (final IOException e) {
      ClientLogger.logQuietly(e);
    }
  }

static Document parseInputStream(@Nullable InputStream input, @Nullable String charsetName, String baseUri, Parser parser) throws IOException  {
        if (input == null) // empty body
            return new Document(baseUri);
        input = ConstrainableInputStream.wrap(input, bufferSize, 0);

        @Nullable Document doc = null;

        // read the start of the stream and look for a BOM or meta charset
        input.mark(bufferSize);
        ByteBuffer firstBytes = readToByteBuffer(input, firstReadBufferSize - 1); // -1 because we read one more to see if completed. First read is < buffer size, so can't be invalid.
        boolean fullyRead = (input.read() == -1);
        input.reset();

        // look for BOM - overrides any other header or input
        BomCharset bomCharset = detectCharsetFromBom(firstBytes);
        if (bomCharset != null)
            charsetName = bomCharset.charset;

        if (charsetName == null) { // determine from meta. safe first parse as UTF-8
            try {
                CharBuffer defaultDecoded = UTF_8.decode(firstBytes);
                if (defaultDecoded.hasArray())
                    doc = parser.parseInput(new CharArrayReader(defaultDecoded.array(), defaultDecoded.arrayOffset(), defaultDecoded.limit()), baseUri);
                else
                    doc = parser.parseInput(defaultDecoded.toString(), baseUri);
            } catch (UncheckedIOException e) {
                throw e.ioException();
            }

            // look for <meta http-equiv="Content-Type" content="text/html;charset=gb2312"> or HTML5 <meta charset="gb2312">
            Elements metaElements = doc.select("meta[http-equiv=content-type], meta[charset]");
            String foundCharset = null; // if not found, will keep utf-8 as best attempt
            for (Element meta : metaElements) {
                if (meta.hasAttr("http-equiv"))
                    foundCharset = getCharsetFromContentType(meta.attr("content"));
                if (foundCharset == null && meta.hasAttr("charset"))
                    foundCharset = meta.attr("charset");
                if (foundCharset != null)
                    break;
            }

            // look for <?xml encoding='ISO-8859-1'?>
            if (foundCharset == null && doc.childNodeSize() > 0) {
                Node first = doc.childNode(0);
                XmlDeclaration decl = null;
                if (first instanceof XmlDeclaration)
                    decl = (XmlDeclaration) first;
                else if (first instanceof Comment) {
                    Comment comment = (Comment) first;
                    if (comment.isXmlDeclaration())
                        decl = comment.asXmlDeclaration();
                }
                if (decl != null) {
                    if (decl.name().equalsIgnoreCase("xml"))
                        foundCharset = decl.attr("encoding");
                }
            }
            foundCharset = validateCharset(foundCharset);
            if (foundCharset != null && !foundCharset.equalsIgnoreCase(defaultCharsetName)) { // need to re-decode. (case insensitive check here to match how validate works)
                foundCharset = foundCharset.trim().replaceAll("[\"']", "");
                charsetName = foundCharset;
                doc = null;
            } else if (!fullyRead) {
                doc = null;
            }
        } else { // specified by content type header (or by user on file load)
            Validate.notEmpty(charsetName, "Must set charset arg to character set of file to parse. Set to null to attempt to detect from HTML");
        }
        if (doc == null) {
            if (charsetName == null)
                charsetName = defaultCharsetName;
            BufferedReader reader = new BufferedReader(new InputStreamReader(input, charsetName), bufferSize);
            if (bomCharset != null && bomCharset.offset) { // creating the buffered reader ignores the input pos, so must skip here
                long skipped = reader.skip(1);
                Validate.isTrue(skipped == 1); // WTF if this fails.
            }
            try {
                doc = parser.parseInput(reader, baseUri);
            } catch (UncheckedIOException e) {
                // io exception when parsing (not seen before because reading the stream as we go)
                throw e.ioException();
            }
            Charset charset = charsetName.equals(defaultCharsetName) ? UTF_8 : Charset.forName(charsetName);
            doc.outputSettings().charset(charset);
            if (!charset.canEncode()) {
                // some charsets can read but not encode; switch to an encodable charset and update the meta el
                doc.charset(UTF_8);
            }
        }
        input.close();
        return doc;
    }

@Override
    public List<DashboardGroup> getDashboardGroups(final TenantIdentifier tenant) {
        final RepositoryFolder timelinesFolder = _tenantContextFactory.getContext(tenant).getTimelineFolder();
        final List<RepositoryFolder> folders = timelinesFolder.getFolders();
        final List<DashboardGroup> groups = new ArrayList<DashboardGroup>();
        for (RepositoryFolder folder : folders) {
            final DashboardGroup group = new DashboardGroup(folder.getName());

            final RepositoryFile descriptionFile = folder.getFile("description.txt");
            if (descriptionFile == null) {
                logger.debug("No description file for timeline group: {}", group);
            } else {
                descriptionFile.readFile(new Action<InputStream>() {
                    @Override
                    public void run(InputStream in) throws Exception {
                        final BufferedReader reader = new BufferedReader(new InputStreamReader(in));
                        final StringBuilder sb = new StringBuilder();
                        try {
                            boolean first = false;
                            for (String line = reader.readLine(); line != null; line = reader.readLine()) {
                                if (first) {
                                    first = false;
                                } else {
                                    sb.append('\n');
                                }
                                sb.append(line);
                            }
                            group.setDescription(sb.toString());
                        } catch (Exception e) {
                            logger.error("Error while reading timeline group description file: " + descriptionFile, e);
                        }

                        reader.close();
                    }
                });
            }

            groups.add(group);
        }
        return groups;
    }

