public static byte[] getFileAsBytes(File file) throws IOException 
    {
        InputStream is = new FileInputStream(file);

        long length = file.length();

        if (length > Integer.MAX_VALUE) 
            return null;

        // Create the byte array to hold the data
        byte[] bytes = new byte[(int)length];

        // Read in the bytes
        int offset = 0;
        int numRead = 0;
        while ( (offset < bytes.length) &&
                ( (numRead=is.read(bytes, offset, bytes.length-offset)) >= 0) ) {
            offset += numRead;
        }

        if (offset < bytes.length) {
            throw new IOException("Could not read file " + file.getName());
        }

        is.close();

        return bytes;
    }

public synchronized void processFile(FileInfo file) {
        try {
            boolean checkFileAge = connectorProperties.isCheckFileAge();
            if (checkFileAge) {
                long fileAge = Long.valueOf(connectorProperties.getFileAge());
                long lastMod = file.getLastModified();
                long now = System.currentTimeMillis();
                if ((now - lastMod) < fileAge)
                    return;
            }

            long fileSize = file.getSize();

            if (fileSize < fileSizeMinimum) {
                return;
            }
            if (!connectorProperties.isIgnoreFileSizeMaximum() && fileSize > fileSizeMaximum) {
                return;
            }

            // Add the original filename to the channel map
            originalFilename = file.getName();
            Map<String, Object> sourceMap = new HashMap<String, Object>();
            sourceMap.put("originalFilename", originalFilename);
            sourceMap.put("fileDirectory", file.getParent());
            sourceMap.put("fileSize", file.getSize());
            sourceMap.put("fileLastModified", file.getLastModified());

            // Set the default file action
            FileAction action = FileAction.NONE;

            boolean errorResponse = false;

            // Perform some quick checks to make sure file can be processed
            if (file.isDirectory()) {
                // ignore directories
            } else if (!(file.isReadable() && file.isFile())) {
                // it's either not readable, or something odd like a link */
                throw new FileConnectorException("File is not readable.");
            } else {
                Exception fileProcessedException = null;
                boolean error = false;

                try {
                    Response response = null;

                    // ast: use the user-selected encoding
                    if (isProcessBatch()) {
                        FileSystemConnection con = fileConnector.getConnection(uri, null, username, password);
                        Reader in = null;
                        try {
                            in = new InputStreamReader(con.readFile(file.getName(), file.getParent()), charsetEncoding);
                            BatchRawMessage batchRawMessage = new BatchRawMessage(new BatchMessageReader(in), sourceMap);

                            dispatchBatchMessage(batchRawMessage, null);
                        } finally {
                            if (in != null) {
                                in.close();
                            }
                            con.closeReadFile();
                            fileConnector.releaseConnection(uri, con, null, username, password);
                        }
                    } else {
                        RawMessage rawMessage;
                        if (connectorProperties.isBinary()) {
                            rawMessage = new RawMessage(getBytesFromFile(file));
                        } else {
                            rawMessage = new RawMessage(new String(getBytesFromFile(file), charsetEncoding));
                        }

                        rawMessage.setSourceMap(sourceMap);

                        DispatchResult dispatchResult = null;
                        try {
                            dispatchResult = dispatchRawMessage(rawMessage);
                        } finally {
                            finishDispatch(dispatchResult);
                        }

                        response = dispatchResult.getSelectedResponse();
                    }

                    // True if the response status is ERROR and we're not processing a batch
                    errorResponse = response != null && response.getStatus() == Status.ERROR;
                } catch (Exception e) {
                    error = true;
                    logger.error("Unable to dispatch message to channel " + getChannelId() + ": " + ExceptionUtils.getStackTrace(e));
                } catch (Throwable t) {
                    error = true;
                    String errorMessage = "Error reading file " + file.getAbsolutePath() + "\n" + t.getMessage();
                    logger.error(errorMessage);
                    fileProcessedException = new FileConnectorException(errorMessage, t);
                }

                boolean shouldUseErrorFields = false;

                // If the message wasn't successfully processed through the channel, set the error file action
                if (error) {
                    action = connectorProperties.getErrorReadingAction();
                    shouldUseErrorFields = true;
                } else if (errorResponse && connectorProperties.getErrorResponseAction() != FileAction.AFTER_PROCESSING) {
                    action = connectorProperties.getErrorResponseAction();
                    shouldUseErrorFields = true;
                } else {
                    action = connectorProperties.getAfterProcessingAction();
                }

                // Move or delete the file based on the selected file action
                if (action == FileAction.MOVE) {
                    // Replace and set the directory/filename
                    String destinationDir = shouldUseErrorFields ? errorMoveToDirectory : moveToDirectory;
                    String destinationName = shouldUseErrorFields ? errorMoveToFileName : moveToFileName;

                    // If the user-specified directory is blank, use the default (file's current directory)
                    if (StringUtils.isNotBlank(destinationDir)) {
                        destinationDir = replacer.replaceValues(destinationDir, getChannelId(), sourceMap);
                    } else {
                        destinationDir = file.getParent();
                    }

                    // If the user-specified filename is blank, use the default (original filename)
                    if (StringUtils.isNotBlank(destinationName)) {
                        destinationName = replacer.replaceValues(destinationName, getChannelId(), sourceMap);
                    } else {
                        destinationName = originalFilename;
                    }

                    if (!filesEqual(file.getParent(), originalFilename, destinationDir, destinationName)) {
                        if (shouldUseErrorFields) {
                            logger.error("Moving file to error directory: " + destinationDir);
                        }

                        // Delete the destination file if it exists, and then rename the original file
                        deleteFile(destinationName, destinationDir, true);
                        boolean resultOfFileMoveOperation = renameFile(file.getName(), file.getParent(), destinationName, destinationDir);

                        if (!resultOfFileMoveOperation) {
                            throw new FileConnectorException("Error moving file from [" + pathname(file.getName(), file.getParent()) + "] to [" + pathname(destinationName, destinationDir) + "]");
                        }
                    }
                } else if (action == FileAction.DELETE) {
                    // Delete the original file
                    boolean resultOfFileMoveOperation = deleteFile(file.getName(), file.getParent(), false);

                    if (!resultOfFileMoveOperation) {
                        throw new FileConnectorException("Error deleting file from [" + pathname(file.getName(), file.getParent()) + "]");
                    }
                }

                if (fileProcessedException != null) {
                    throw fileProcessedException;
                }
            }
        } catch (Exception e) {
            eventController.dispatchEvent(new ErrorEvent(getChannelId(), getMetaDataId(), 12345L, ErrorEventType.SOURCE_CONNECTOR, getSourceName(), connectorProperties.getName(), "", e));
            logger.error("Error processing file in channel: " + getChannelId(), e);
        }
    }

public static Properties loadProps(String resourceName) {
		InputStream in = PropertiesLoader.class.getClassLoader().getResourceAsStream(resourceName);
		Properties props = new Properties();
		if (in != null) {
			try {
				props.load(in);
				in.close();
			} catch (IOException e) {
				e.printStackTrace();
			}
		}
		return props;
	}

private void process(String urlSource, String urlTarget,
            String user, String password, String serverList) throws SQLException {
        Connection connSource = null, connTarget = null;
        Statement statSource = null, statTarget = null;

        try {
            org.h2.Driver.load();

            // verify that the database doesn't exist,
            // or if it exists (an old cluster instance), it is deleted
            boolean exists = true;
            try {
                connTarget = DriverManager.getConnection(urlTarget +
                        ";IFEXISTS=TRUE;CLUSTER=" + Constants.CLUSTERING_ENABLED,
                        user, password);
                Statement stat = connTarget.createStatement();
                stat.execute("DROP ALL OBJECTS DELETE FILES");
                stat.close();
                exists = false;
                connTarget.close();
            } catch (SQLException e) {
                if (e.getErrorCode() == ErrorCode.DATABASE_NOT_FOUND_1) {
                    // database does not exists yet - ok
                    exists = false;
                } else {
                    throw e;
                }
            }
            if (exists) {
                throw new SQLException(
                        "Target database must not yet exist. Please delete it first: " +
                        urlTarget);
            }

            // use cluster='' so connecting is possible
            // even if the cluster is enabled
            connSource = DriverManager.getConnection(urlSource +
                    ";CLUSTER=''", user, password);
            statSource = connSource.createStatement();

            // enable the exclusive mode and close other connections,
            // so that data can't change while restoring the second database
            statSource.execute("SET EXCLUSIVE 2");

            try {

                // Delete the target database first.
                connTarget = DriverManager.getConnection(
                        urlTarget + ";CLUSTER=''", user, password);
                statTarget = connTarget.createStatement();
                statTarget.execute("DROP ALL OBJECTS DELETE FILES");
                connTarget.close();

                // Backup data from source database in script form.
                // Start writing to script pipe output end in separate thread.
                // Variables used from inner class must be final.
                final PipedReader pipeReader = new PipedReader();
                final ResultSet rs = statSource.executeQuery("SCRIPT");

                new Thread(
                    new Runnable(){
                        public void run() {
                            try {
                                PipedWriter pipeWriter = new PipedWriter(pipeReader);
                                while (rs.next()) {
                                    pipeWriter.write(rs.getString(1) + "\n");
                                }
                                pipeWriter.close();
                            } catch (Exception e ) {
                                throw new IllegalStateException("Producing script from the source DB is failing.");
                            }
                        }
                    }
                ).start();

                // Read data from script pipe input end, restore on target.
                connTarget = DriverManager.getConnection(urlTarget, user, password);
                RunScript runScript = new RunScript();
                runScript.setOut(out);
                runScript.execute(connTarget,pipeReader);
                statTarget = connTarget.createStatement();

                // set the cluster to the serverList on both databases
                statSource.executeUpdate("SET CLUSTER '" + serverList + "'");
                statTarget.executeUpdate("SET CLUSTER '" + serverList + "'");
            } finally {

                // switch back to the regular mode
                statSource.execute("SET EXCLUSIVE FALSE");
            }
        } finally {
            JdbcUtils.closeSilently(statSource);
            JdbcUtils.closeSilently(statTarget);
            JdbcUtils.closeSilently(connSource);
            JdbcUtils.closeSilently(connTarget);
        }
    }

@Override
    public Object getConvertedValue(FacesContext context, UIComponent component, Object submittedValue) throws ConverterException {
        String coords = (String) submittedValue;

        if (isValueBlank(coords)) {
            return null;
        }

        String[] cropCoords = coords.split("_");

        int x = (int) Double.parseDouble(cropCoords[0]);
        int y = (int) Double.parseDouble(cropCoords[1]);
        int w = (int) Double.parseDouble(cropCoords[2]);
        int h = (int) Double.parseDouble(cropCoords[3]);

        if (w <= 0 || h <= 0) {
            return null;
        }

        ImageCropper cropper = (ImageCropper) component;
        Resource resource = getImageResource(context, cropper);
        InputStream inputStream;
        String imagePath = cropper.getImage();
        String contentType = null;

        try {

            if (resource != null && !"RES_NOT_FOUND".equals(resource.toString())) {
                inputStream = resource.getInputStream();
                contentType = resource.getContentType();
            }
            else {

                boolean isExternal = imagePath.startsWith("http");

                if (isExternal) {
                    URL url = new URL(imagePath);
                    URLConnection urlConnection = url.openConnection();
                    inputStream = urlConnection.getInputStream();
                    contentType = urlConnection.getContentType();
                }
                else {
                    ExternalContext externalContext = context.getExternalContext();
                    File file = new File(externalContext.getRealPath("") + imagePath);
                    inputStream = new FileInputStream(file);
                }
            }

            // wrap input stream by BoundedInputStream to prevent uncontrolled resource consumption (#3286)
            if (cropper.getSizeLimit() != null) {
                inputStream = new BoundedInputStream(inputStream, cropper.getSizeLimit());
            }

            BufferedImage outputImage = ImageIO.read(inputStream);
            inputStream.close();

            // avoid java.awt.image.RasterFormatException: (x + width) is outside of Raster
            // see #1208
            if (x + w > outputImage.getWidth()) {
                w = outputImage.getWidth() - x;
            }
            if (y + h > outputImage.getHeight()) {
                h = outputImage.getHeight() - y;
            }

            BufferedImage cropped = outputImage.getSubimage(x, y, w, h);
            ByteArrayOutputStream croppedOutImage = new ByteArrayOutputStream();
            String format = guessImageFormat(contentType, imagePath);
            ImageIO.write(cropped, format, croppedOutImage);

            return new CroppedImage(cropper.getImage(), croppedOutImage.toByteArray(), x, y, w, h);
        }
        catch (IOException e) {
            throw new ConverterException(e);
        }
    }

public void concat(String outputFileName) throws FileNotFoundException, IOException
	{

		// Calculate dependencies
		FileOutputStream outStream = new FileOutputStream(outputFileName);

		// Create a list of input streams
		ArrayList<InputStream> inputStreams = new ArrayList<InputStream>();
		for (FileNode fileNode : fileNodes)
			inputStreams.add(new FileInputStream(fileNode.file));

		SequenceInputStream input = new SequenceInputStream(Collections.enumeration(inputStreams));		

		// Copy in->out.
		byte[] buf = new byte[1024];
		int len;
		while ((len=input.read(buf))!=-1) outStream.write(buf, 0, len);

		input.close();
		outStream.close();		
	}

public byte[][] getAnnexBFrameHeader(InputFile f) {
		String[] cmdArray = new String[14];
		cmdArray[0] = configuration.getFfmpegPath();
		cmdArray[1] = "-i";

		if (f.getPush() == null && f.getFilename() != null) {
			cmdArray[2] = f.getFilename();
		} else {
			cmdArray[2] = "-";
		}

		cmdArray[3] = "-vframes";
		cmdArray[4] = "1";
		cmdArray[5] = "-c:v";
		cmdArray[6] = "copy";
		cmdArray[7] = "-f";
		cmdArray[8] = "h264";
		cmdArray[9] = "-bsf";
		cmdArray[10] = "h264_mp4toannexb";
		cmdArray[11] = "-an";
		cmdArray[12] = "-y";
		cmdArray[13] = "pipe:";

		byte[][] returnData = new byte[2][];
		OutputParams params = new OutputParams(configuration);
		params.maxBufferSize = 1;
		params.stdin = f.getPush();

		final ProcessWrapperImpl pw = new ProcessWrapperImpl(cmdArray, params);

		Runnable r = new Runnable() {
			@Override
			public void run() {
				try {
					Thread.sleep(3000);
					ffmpeg_annexb_failure = true;
				} catch (InterruptedException e) { }
				pw.stopProcess();
			}
		};

		Thread failsafe = new Thread(r, "FFMpeg AnnexB Frame Header Failsafe");
		failsafe.start();
		pw.runInSameThread();

		if (ffmpeg_annexb_failure) {
			return null;
		}

		InputStream is;
		ByteArrayOutputStream baot = new ByteArrayOutputStream();

		try {
			is = pw.getInputStream(0);
			byte b[] = new byte[4096];
			int n;

			while ((n = is.read(b)) > 0) {
				baot.write(b, 0, n);
			}

			byte data[] = baot.toByteArray();
			baot.close();
			returnData[0] = data;
			is.close();
			int kf = 0;

			for (int i = 3; i < data.length; i++) {
				if (data[i - 3] == 1 && (data[i - 2] & 37) == 37 && (data[i - 1] & -120) == -120) {
					kf = i - 2;
					break;
				}
			}

			int st = 0;
			boolean found = false;

			if (kf > 0) {
				for (int i = kf; i >= 5; i--) {
					if (data[i - 5] == 0 && data[i - 4] == 0 && data[i - 3] == 0 && (data[i - 2] & 1) == 1 && (data[i - 1] & 39) == 39) {
						st = i - 5;
						found = true;
						break;
					}
				}
			}

			if (found) {
				byte header[] = new byte[kf - st];
				System.arraycopy(data, st, header, 0, kf - st);
				returnData[1] = header;
			}
		} catch (IOException e) {
			LOGGER.debug("Caught exception", e);
		}

		return returnData;
	}

public void exportProject(HttpServletRequest request,
							  HttpServletResponse response) throws Exception {

		Permissions.ensureAdmin(Common.getUser(request));
		extractExportParametersFromRequest(request);

		response.setHeader("Content-Disposition", "attachment; filename="
				+ projectName.replaceAll(" ", "") + ".zip");

		List<FileToPack> tempFiles = new ArrayList<>();

		tempFiles.add(buildProjectDescriptionFile(projectName, projectDescription));
		tempFiles.add(buildJSONFile(JSON_FILE_NAME, includePointValues));

		List<FileToPack> filesToZip = new ArrayList<>();
		if (includeUploadsFolder)
			filesToZip.addAll(getUploadsFolderFiles());

		if (includeGraphicsFolder)
			filesToZip.addAll(getGraphicsFolderFiles());

		filesToZip.addAll(tempFiles);

		ServletOutputStream out = response.getOutputStream();
		FileUtil.compactFiles(out,
				filesToZip.toArray(new FileToPack[filesToZip.size()]));

		deleteFiles(tempFiles);
	}

