public void copyFileWithPIReplaced(final File src, final File target, final File copytoTargetFilename, final File inputMapInTemp ) {
        if (!target.getParentFile().exists() && !target.getParentFile().mkdirs()) {
            logger.logError("Failed to create copy-to target directory " + target.getParentFile().getAbsolutePath());
        }
        final DitaWriter dw = new DitaWriter();
        dw.setJob(job);
        final String path2project = dw.getPathtoProject(copytoTargetFilename, target, inputMapInTemp);
        final File workdir = target.getParentFile();
        try {
            final Transformer serializer = TransformerFactory.newInstance().newTransformer();
            final XMLFilter filter = new CopyToFilter(StringUtils.getXMLReader(), workdir, path2project);
            serializer.transform(new SAXSource(filter, new InputSource(src.toURI().toString())),
                                 new StreamResult(target));
        } catch (final TransformerConfigurationException e) {
            logger.logError("Failed to configure serializer: " + e.getMessage(), e);
        } catch (final TransformerFactoryConfigurationError e) {
            logger.logError("Failed to configure serializer: " + e.getMessage(), e);
        } catch (final SAXException e) {
            logger.logError("Failed to create XML parser: " + e.getMessage(), e);
        } catch (final TransformerException e) {
            logger.logError("Failed to rewrite copy-to file: " + e.getMessage(), e);
        }
    }

@Override
        public List<Class<?>> call() throws Exception {
            try {
                if (LOGGER.isLoggable(Level.FINEST)) {
                    LOGGER.log(Level.FINEST, "Loading providers for SPI: {0}", spi);
                }
                final BufferedReader br = new BufferedReader(new InputStreamReader(spiRegistryUrl.openStream(), "UTF-8"));
                String providerClassName;
                final List<Class<?>> providerClasses = new ArrayList<Class<?>>();
                while ((providerClassName = br.readLine()) != null) {
                    if (providerClassName.trim().length() == 0) {
                        continue;
                    }
                    if (LOGGER.isLoggable(Level.FINEST)) {
                        LOGGER.log(Level.FINEST, "SPI provider: {0}", providerClassName);
                    }
                    providerClasses.add(loadClass(bundle, providerClassName));
                }
                br.close();
                return providerClasses;
            } catch (Exception e) {
                LOGGER.log(Level.WARNING, LocalizationMessages.EXCEPTION_CAUGHT_WHILE_LOADING_SPI_PROVIDERS(), e);
                throw e;
            } catch (Error e) {
                LOGGER.log(Level.WARNING, LocalizationMessages.ERROR_CAUGHT_WHILE_LOADING_SPI_PROVIDERS(), e);
                throw e;
            }
        }

public static FileSet getTransferFiles(Transferable transferable) {
        FileSet files;
        AbstractFile file;

        try {
            // FileSet DataFlavor
            if(transferable.isDataFlavorSupported(FILE_SET_DATA_FLAVOR)) {
                files = (FileSet)transferable.getTransferData(FILE_SET_DATA_FLAVOR);
            }
            // File list DataFlavor
            else if(transferable.isDataFlavorSupported(DataFlavor.javaFileListFlavor)) {
                List fileList = (List)transferable.getTransferData(DataFlavor.javaFileListFlavor);

                int nbFiles = fileList.size();
                files = new FileSet();
                for(int i=0; i<nbFiles; i++) {
                    file = FileFactory.getFile(((File)fileList.get(i)).getAbsolutePath());

                    if(file!=null)
                        files.add(file);
                }
            }
            // Text plain DataFlavor: assume that lines designate file paths
            else if(transferable.isDataFlavorSupported(DataFlavor.stringFlavor)) {
                BufferedReader br = new BufferedReader(DataFlavor.getTextPlainUnicodeFlavor().getReaderForText(transferable));

                // Read input line by line and try to create AbstractFile instances
                String path;
                files = new FileSet();
                while((path=br.readLine())!=null) {
                    // Try to create an AbstractFile instance, returned instance may be null
                    file = FileFactory.getFile(path);

                    // Safety precaution: if at least one line doesn't resolve as a file, stop reading
                    // and return null. This is to avoid any nasty effect that could arise if a random
                    // piece of text (let's say an email contents) was inadvertently pasted or dropped to muCommander.
                    if(file==null)
                        return null;

                    files.add(file);
                }

                br.close();
            }
            else {
                return null;
            }
        }
        catch(Exception e) {
            // Catch UnsupportedFlavorException, IOException
            if(Debug.ON) Debug.trace("Caught exception while processing transferable: "+e);

            return  null;
        }

        return files;
    }

