public ResourceBundle getResourceBundle(final String bundleName) {
        final int lastDotIndex = bundleName.lastIndexOf('.');
        final String path = bundleName.substring(0, lastDotIndex).replace('.', '/');
        final String propertiesName = bundleName.substring(lastDotIndex + 1, bundleName.length()) + ".properties";
        for (Bundle bundle : bundleContext.getBundles()) {
            final Enumeration<URL> entries = findEntries(bundle, path, propertiesName, false);
            if (entries != null && entries.hasMoreElements()) {
                final URL entryUrl = entries.nextElement();
                try {
                    return new PropertyResourceBundle(entryUrl.openStream());
                } catch (IOException ex) {
                    if (LOGGER.isLoggable(Level.FINE)) {
                        // does not make sense to localize this
                        LOGGER.fine("Exception caught when tried to load resource bundle in OSGi");
                    }
                    return null;
                }
            }
        }
        return null;
    }

protected static InputStream getResourceAsStream(ClassLoader loader, String name) {
        if (loader != null) {
            return loader.getResourceAsStream(name);
        } else {
            return ClassLoader.getSystemResourceAsStream(name);
        }
    }

public static <T> List<T> load(String name, Class<?> clazz) {
        LOG.info("Looking for a resource file of name [{}] ...", name);
        List<T> services = new ArrayList<>();
        try {
            final InputStream is = getResourceAsStream(getContextClassLoader(), name);
            if (is != null) {
                BufferedReader reader;
                reader = new BufferedReader(new InputStreamReader(is, StandardCharsets.UTF_8));
                String serviceName = reader.readLine();
                List<String> names = new ArrayList<>();
                while (serviceName != null && !"".equals(serviceName)) {
                    LOG.info(
                        "Creating an instance as specified by file {} which was present in the path of the context classloader.",
                        name);
                    if (!names.contains(serviceName)) {
                        names.add(serviceName);
                        services.add(initService(getContextClassLoader(), serviceName, clazz));
                    }
                    serviceName = reader.readLine();
                }
                reader.close();
            } else {
                // is == null
                LOG.warn("No resource file with name [{}] found.", name);
            }
        } catch (Exception e) {
            LOG.error("Error occurred when looking for resource file " + name, e);
        }
        return services;
    }

mportKFF(File kffDir) throws IOException {

        File NSRLProd = new File(kffDir, "NSRLProd.txt"); //$NON-NLS-1$
        BufferedReader reader = new BufferedReader(new FileReader(NSRLProd));
        String line = reader.readLine();
        while ((line = reader.readLine()) != null) {
            int idx = line.indexOf(',');
            String key = line.substring(0, idx);
            String[] values = line.substring(idx + 2).split("\",\""); //$NON-NLS-1$
            String[] prod = { values[0], values[1] };
            products.put(Integer.valueOf(key), prod);
        }
        reader.close();
        for (File kffFile : kffDir.listFiles()) {
            if (!kffFile.getName().equals("NSRLFile.txt")) { //$NON-NLS-1$
                continue;
            }
            long length = kffFile.length();
            long progress = 0;
            int i = 0;
            ProgressMonitor monitor = new ProgressMonitor(null, "", "Importing " + kffFile.getName(), 0, //$NON-NLS-1$ //$NON-NLS-2$
                    (int) (length / 1000));
            reader = new BufferedReader(new FileReader(kffFile));
            line = reader.readLine();
            String[] ignoreStrs = { "\"\"", "\"D\"" }; //$NON-NLS-1$ //$NON-NLS-2$
            while ((line = reader.readLine()) != null) {
                String[] values = line.split(","); //$NON-NLS-1$
                KffAttr attr = new KffAttr();
                attr.group = Integer.valueOf(values[values.length - 3]);
                if (values[values.length - 1].equals(ignoreStrs[0])
                        || values[values.length - 1].equals(ignoreStrs[1])) {
                    attr.group *= -1;
                }
                // else
                // System.out.println(line);

                HashValue md5 = new HashValue(values[1].substring(1, 33));
                HashValue sha1 = new HashValue(values[0].substring(1, 41));

                Integer value = md5Map.get(md5);
                if (value == null || (value > 0 && attr.group < 0)) {
                    md5Map.put(md5, attr.group);
                    sha1Map.put(sha1, attr.group);
                }

                progress += line.length() + 2;
                if (progress > i * length / 1000) {
                    if (monitor.isCanceled()) {
                        return;
                    }
                    monitor.setProgress((int) (progress / 1000));
                    i++;
                }

            }
            reader.close();
            db.commit();
            db.close();
            monitor.close();
        }
    }

