            return ClassLoader.getSystemResourceAsStream(name);
        }
    }

@Override
    public int write(DataOutputStream out) throws IOException {
        // prepare payload
        ByteArrayOutputStream byteOut = new ByteArrayOutputStream();
        DataOutputStream packetOut = new DataOutputStream(byteOut);
        final byte[] data = mData.getData();

        // ISO 14443 header (4 bytes)
        // version
        packetOut.writeByte(0);
        // event
        packetOut.writeByte(mData.isCard() ? DATA_PICC_TO_PCD_CRC_DROPPED :
                DATA_PCD_TO_PICC_CRC_DROPPED);
        // len (data len + 1 byte for I_BLOCK PCB)
        packetOut.writeShort(data.length + 1);

        // part of frame
        // I_BLOCK PCB: 0000010
        packetOut.writeByte(0x02);
        // actual data
        packetOut.write(data);
        packetOut.close();

        mInterfaceIndex = mData.isInitial() ? 1 : 0;
        mPayload = byteOut.toByteArray();
        mTimestamp = mData.getTimestamp();
        return super.write(out);
    }

public static List<File> getYarnDeployDependencies() throws IOException {
    InputStream dependencyTree = ApexRunner.class.getResourceAsStream("dependency-tree");
    BufferedReader br = new BufferedReader(new InputStreamReader(dependencyTree));
    String line = null;
    List<String> excludes = new ArrayList<>();
    int excludeLevel = Integer.MAX_VALUE;
    while ((line = br.readLine()) != null) {
      for (int i = 0; i < line.length(); i++) {
        char c = line.charAt(i);
        if (Character.isLetter(c)) {
          if (i > excludeLevel) {
            excludes.add(line.substring(i));
          } else {
            if (line.substring(i).startsWith("org.apache.hadoop")) {
              excludeLevel = i;
              excludes.add(line.substring(i));
            } else {
              excludeLevel = Integer.MAX_VALUE;
            }
          }
          break;
        }
      }
    }
    br.close();

    Set<String> excludeJarFileNames = Sets.newHashSet();
    for (String exclude : excludes) {
      String[] mvnc = exclude.split(":");
      String fileName = mvnc[1] + "-";
      if (mvnc.length == 6) {
        fileName += mvnc[4] + "-" + mvnc[3]; // with classifier
      } else {
        fileName += mvnc[3];
      }
      fileName += ".jar";
      excludeJarFileNames.add(fileName);
    }

    ClassLoader classLoader = ApexYarnLauncher.class.getClassLoader();
    URL[] urls = ((URLClassLoader) classLoader).getURLs();
    List<File> dependencyJars = new ArrayList<>();
    for (int i = 0; i < urls.length; i++) {
      File f = new File(urls[i].getFile());
      // dependencies can also be directories in the build reactor,
      // the Apex client will automatically create jar files for those.
      if (f.exists() && !excludeJarFileNames.contains(f.getName())) {
          dependencyJars.add(f);
      }
    }
    return dependencyJars;
  }

private void saveToFile(ResContainer rc, File outFile) {
		CodeWriter cw = rc.getContent();
		if (cw != null) {
			cw.save(outFile);
			return;
		}
		InputStream binary = rc.getBinary();
		if(binary != null) {
			try {
				outFile.getParentFile().mkdirs();
				FileOutputStream binaryFileStream = new FileOutputStream(outFile);
				IOUtils.copy(binary, binaryFileStream);
				binaryFileStream.close();
				binary.close();
			}
			catch(IOException e) {
				LOG.warn("Resource '{}' not saved, got exception {}", rc.getName(), e);
			}
			return;
		}
		LOG.warn("Resource '{}' not saved, unknown type", rc.getName());
	}

